package kr.gampa.battlegrounds.combat; import java.util.*; public final class FireModeState{private final List<String> modes;private int index;public FireModeState(String current,List<String> modes){if(modes==null||modes.isEmpty())throw new IllegalArgumentException();this.modes=List.copyOf(modes);this.index=Math.max(0,this.modes.indexOf(current));}public String cycle(){index=(index+1)%modes.size();return modes.get(index);}public String current(){return modes.get(index);}}